# Homebrew formula for ccx (cc-context). Installs the prebuilt binary for the
# current platform from cc-context's GitHub Releases — no Go toolchain needed.
# `brew install --HEAD` builds (pure Go) from source instead.
#
#   brew install yasyf/tap/ccx
#
# This file is generated by cc-context's release.yml from .github/formula/ccx.rb.tmpl
# on every stable tag — edit the template there, not the tap copy. The release job
# fills the version placeholder with the v-stripped release version and the four
# per-platform sha256 placeholders with the archive checksums from dist/checksums.txt.
class Ccx < Formula
  desc "Compact codebase-context tools for AI agents"
  homepage "https://github.com/yasyf/cc-context"
  version "0.6.0"
  license "PolyForm-Noncommercial-1.0.0"

  livecheck do
    url :stable
    strategy :github_latest
  end

  head do
    url "https://github.com/yasyf/cc-context.git", branch: "main"
    depends_on "go" => :build
  end

  # ast-grep powers the structural search/replace engine; uv runs semble (via uvx)
  # for the semantic search/related ops and the pydantic-monty driver for the
  # ccx exec sandbox. Both are required at runtime.
  depends_on "ast-grep"
  depends_on "uv"

  on_macos do
    on_arm do
      url "https://github.com/yasyf/cc-context/releases/download/v#{version}/ccx_#{version}_darwin_arm64.tar.gz"
      sha256 "b7f53e44f64baaec5992f66a8dd6851d9f1e153e90b74fda43538af300f792e2"
    end
    on_intel do
      url "https://github.com/yasyf/cc-context/releases/download/v#{version}/ccx_#{version}_darwin_amd64.tar.gz"
      sha256 "1712b0fbc747cf61dd60e23bfea626113f0155a14dd155f30513ef6c0275781c"
    end
  end

  on_linux do
    on_arm do
      url "https://github.com/yasyf/cc-context/releases/download/v#{version}/ccx_#{version}_linux_arm64.tar.gz"
      sha256 "8d65e5b42fed1e7653124acf03ab98c6a3cedff26206644a52422030cfa9b2e9"
    end
    on_intel do
      url "https://github.com/yasyf/cc-context/releases/download/v#{version}/ccx_#{version}_linux_amd64.tar.gz"
      sha256 "f5c9e38899615b557d649b6fb639fee626288d22fad76e2b16e3e0fba65f81f8"
    end
  end

  def install
    if build.head?
      ENV["CGO_ENABLED"] = "0"
      ldflags = "-s -w -X github.com/yasyf/cc-context/internal/version.Version=#{version}"
      system "go", "build", *std_go_args(ldflags: ldflags, output: bin/"ccx"), "./cmd/ccx"
    else
      # brew auto-extracts the release tarball; install the bare binary.
      bin.install "ccx"
    end
  end

  test do
    assert_match version.to_s, shell_output("#{bin}/ccx --version")
  end
end
